                    Iterator<Long[]> iterator = dispatchJobs.iterator();
                    while (iterator.hasNext()) {
                        Long[] jobHash = iterator.next();
                        int dispatchHash = jobHash[1].intValue();
                        if (dispatchHash <= virtualHashKey) {
